async function process(incomingData, nodeData, params) {
  try {
    const { operation, condition, logicRules } = nodeData;
    const { enableLogging = true, strictMode = false } = params;

    if (enableLogging) {
      console.log(`Processing ${operation} operation with data:`, incomingData);
    }

    // Extract actual data from REST response wrapper if needed
    let actualData = incomingData;
    if (incomingData && typeof incomingData === 'object' && !Array.isArray(incomingData)) {
      if (incomingData.response && Array.isArray(incomingData.response)) {
        actualData = incomingData.response;
      } else if (incomingData.data && Array.isArray(incomingData.data)) {
        actualData = incomingData.data;
      }
    }

    switch (operation.toLowerCase()) {
      case 'filter':
        if (!Array.isArray(actualData)) {
          if (strictMode) {
            throw new Error('Filter operation requires array input');
          }
          return [];
        }

        return actualData.filter((item) => {
          if (logicRules && Array.isArray(logicRules)) {
            // Use structured rules
            return evaluateLogicRules(logicRules, item);
          } else if (condition) {
            // Legacy condition string evaluation
            return evaluateCondition(condition, item);
          }
          return true;
        });

      case 'transform':
        if (!Array.isArray(actualData)) {
          if (strictMode) {
            throw new Error('Transform operation requires array input');
          }
          return [];
        }

        return actualData.map((item) => ({
          ...item,
          transformed: true,
          processedAt: new Date().toISOString(),
          operation: 'transform'
        }));

      case 'aggregate':
        if (!Array.isArray(actualData)) {
          if (strictMode) {
            throw new Error('Aggregate operation requires array input');
          }
          return [{ count: 0, items: [], aggregated: true }];
        }

        return [{
          id: 'aggregate-summary',
          title: `Summary of ${actualData.length} items`,
          count: actualData.length,
          summary: {
            totalItems: actualData.length,
            processedAt: new Date().toISOString()
          },
          aggregated: true,
          originalData: actualData
        }];

      case 'conditional':
        // Route data based on condition
        const passesCondition = actualData && Array.isArray(actualData) 
          ? actualData.some(item => evaluateCondition(condition, item))
          : evaluateCondition(condition, actualData);

        return {
          condition: condition,
          result: passesCondition,
          data: actualData,
          routeTo: passesCondition ? 'true' : 'false'
        };

      case 'validate':
        if (!Array.isArray(actualData)) {
          return [{
            valid: false,
            errors: ['Input must be an array'],
            data: actualData
          }];
        }

        return actualData.map(item => ({
          valid: item && typeof item === 'object',
          errors: [],
          data: item,
          validatedAt: new Date().toISOString()
        }));

      default:
        if (strictMode) {
          throw new Error(`Unknown operation: ${operation}`);
        }
        return actualData || [];
    }

  } catch (error) {
    if (params.enableLogging) {
      console.error('Logic processing error:', error);
    }

    return {
      success: false,
      error: error.message,
      operation: nodeData.operation,
      timestamp: new Date().toISOString()
    };
  }
}

// Helper function to evaluate logic rules
function evaluateLogicRules(rules, item) {
  if (!rules || rules.length === 0) return true;

  let result = true;
  for (let i = 0; i < rules.length; i++) {
    const rule = rules[i];
    const ruleResult = evaluateSingleRule(rule, item);

    if (i === 0) {
      result = ruleResult;
    } else {
      const prevRule = rules[i - 1];
      if (prevRule.logicalOperator === 'OR') {
        result = result || ruleResult;
      } else {
        result = result && ruleResult;
      }
    }
  }

  return result;
}

// Helper function to evaluate a single rule
function evaluateSingleRule(rule, item) {
  const value = item[rule.field];
  const targetValue = rule.value;

  switch (rule.operator) {
    case 'equals': return value === targetValue;
    case 'not_equals': return value !== targetValue;
    case 'greater_than': return value > targetValue;
    case 'less_than': return value < targetValue;
    case 'contains': return String(value).includes(String(targetValue));
    case 'starts_with': return String(value).startsWith(String(targetValue));
    default: return true;
  }
}

// Helper function for legacy condition evaluation
function evaluateCondition(condition, item) {
  if (!condition) return true;

  try {
    // Simple condition evaluation (safe subset)
    if (condition.includes('userId') && condition.includes('<=')) {
      const userIdMatch = item.userId <= 5;
      if (condition.includes('title.length')) {
        const titleLengthMatch = item.title && item.title.length > 10;
        return userIdMatch && titleLengthMatch;
      }
      return userIdMatch;
    }

    return true;
  } catch (error) {
    console.warn('Failed to evaluate condition:', condition, error);
    return true;
  }
}
